StructuredTextModel.Text:
	IF (Enable) THEN
	// ---------- Create the value
	// Combine different IO Link values together
	Value_Word1 := PackWord(Val1[0], Val1[1]);
	Value_Word2 := PackWord(Val2[0], Val2[1]);
	Value_DWORD:= PackDword(HighHigh:=Val1[0], highLow:=Val1[1], LowHigh:=Val2[0], LowLow:=Val2[1]);
	Value_UDINT := DWORD_TO_UDINT(Value_DWORD);
	Value_DINT := DWORD_TO_DINT(Value_DWORD);
	
	// Extract exponent from data
	Exponent_SINT := BYTE_TO_SINT(Data[0]);
	
	// Create real value by uniting the value and the exponent
	Value_REAL := UniteReal(Value_DINT, Exponent_SINT);

	// ---------- Process the value
	// Output raw value for HMI information
	Raw_Value_C := Value_REAL;

	// Reset tonnage value everytime the cam is reset
	Cam_Enable_R(CLK := Cam_Enable);
	IF (Cam_Enable_R.Q) THEN
		Raw_Value_L := 0;
	END_IF;

	// Determine what is the highest value during the stroke
	IF (Cam_Enable) THEN
		IF (Raw_Value_C > Raw_Value_L) THEN
			Raw_Value_L := Raw_Value_C;
		END_IF;
	END_IF;

	// Transform raw value into actual tonnage
	Tonnage := Raw_Value_L*T_Mul;
	Tonnage_C := Raw_Value_C*T_Mul;

	// ---------- Calibration
	// Calibrate the tonnage mulitplier
	Calibrate_R(Clk := Calibrate);
	IF (Calibrate_R.Q) THEN
		T_Mul := T_Calibrate_Real_Val/Raw_Value_L;
	END_IF;

	// Tare the strain link
	// Set tare signal
	Tare_R(CLK := Tare);
	IF (Tare_R.Q) THEN
		SetABit(Out_Comm[0], 3);
	END_IF;
	// Reset
	Tare_TOFF(In := Tare_R.Q, PT := T#1S);
	IF (NOT Tare_TOFF.Q) THEN
		ResetABit(Out_Comm[0], 3);
	END_IF;

	// ---------- Alarm monitoring
	IF ((Error > 1) OR (TestABit(Data[1], 2) OR (TestABit(Data[1], 2)))) THEN
		Alarm := TRUE;
	ELSE
		Alarm := FALSE;
	END_IF;
	
ELSE
	Tonnage := 0;
	Alarm := FALSE;
	Raw_Value_C := 0;
	Raw_Value_L := 0;
END_IF;
